package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Constructor;
import java.lang.reflect.Method;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        // Use DEFAULT format for testing
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testFormat_withNormalValues() throws Exception {
        String result = csvFormat.format("a", "b", "c");
        assertEquals("a,b,c", result);
    }

    @Test
    void testFormat_withNullValues() throws Exception {
        String result = csvFormat.format("a", null, "c");
        // null values are printed as empty strings by default
        assertEquals("a,,c", result);
    }

    @Test
    void testFormat_withEmptyValues() throws Exception {
        String result = csvFormat.format("", "", "");
        assertEquals(",,,", result.replaceAll("[\\r\\n]", "").substring(0,3) + "", "Empty strings separated by commas");
    }

    @Test
    void testFormat_withSingleValue() throws Exception {
        String result = csvFormat.format("single");
        assertEquals("single", result);
    }

    @Test
    void testFormat_withNoValues() throws Exception {
        String result = csvFormat.format();
        assertEquals("", result);
    }

    @Test
    void testFormat_throwsIllegalStateExceptionOnIOException() throws Exception {
        // Mock CSVPrinter to throw IOException on printRecord
        CSVPrinter mockPrinter = mock(CSVPrinter.class);
        doThrow(new IOException("mock IO error")).when(mockPrinter).printRecord(any());

        Constructor<CSVPrinter> constructor = CSVPrinter.class.getDeclaredConstructor(Appendable.class, CSVFormat.class);
        constructor.setAccessible(true);

        CSVFormat format = new CSVFormat(csvFormat.getDelimiter(),
                csvFormat.getQuoteChar(),
                null,
                csvFormat.getCommentStart(),
                csvFormat.getEscape(),
                csvFormat.getIgnoreSurroundingSpaces(),
                csvFormat.getIgnoreEmptyLines(),
                csvFormat.getRecordSeparator(),
                csvFormat.getNullString(),
                csvFormat.getHeader(),
                csvFormat.getSkipHeaderRecord()) {
            @Override
            public String format(Object... values) {
                try {
                    mockPrinter.printRecord(values);
                    return "";
                } catch (IOException e) {
                    throw new IllegalStateException(e);
                }
            }
        };

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> {
            format.format("value");
        });
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("mock IO error", thrown.getCause().getMessage());
    }

    @Test
    void testFormat_reflectionInvoke() throws Exception {
        Method formatMethod = CSVFormat.class.getDeclaredMethod("format", Object[].class);
        formatMethod.setAccessible(true);
        String result = (String) formatMethod.invoke(csvFormat, (Object) new Object[]{"x", "y"});
        assertEquals("x,y", result);
    }

    @Test
    void testFormat_withDifferentCSVFormatInstance() throws Exception {
        // Create CSVFormat instance with different delimiter and quote char using reflection
        Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(char.class, Character.class,
                Object.class, Character.class, Character.class, boolean.class, boolean.class, String.class, String.class, String[].class, boolean.class);
        constructor.setAccessible(true);
        CSVFormat customFormat = constructor.newInstance(';', '"', null, null, null, false, true, "\n", null, null, false);
        String result = customFormat.format("a", "b;c", "c");
        // The value with delimiter should be quoted
        assertEquals("a;\"b;c\";c", result);
    }
}
